mapper.select:
SELECT a.id, a.object_type AS objectType, a.object_id AS objectId, a.year, a.standard_code AS standardCode FROM assessment_result a INNER JOIN ( VALUES
(#{k.objectType}, #{k.objectId}, #{k.year}, #{k.standardCode})
) AS t(object_type, object_id, year, standard_code) ON a.object_type = t.object_type AND a.object_id = t.object_id AND a.year = t.year AND a.standard_code = t.standard_code WHERE a.tenant_id = #{tenantId} AND a.deleted = false

mapper.update:
UPDATE assessment_result AS t SET task_id = d.task_id, route_id = d.route_id, section_id = d.section_id, unit_id = d.unit_id, route_code = d.route_code, direction = d.direction, start_stake = d.start_stake, end_stake = d.end_stake, mqi = d.mqi, sci = d.sci, pqi = d.pqi, bci = d.bci, tci = d.tci, pci = d.pci, rqi = d.rqi, rdi = d.rdi, pbi = d.pbi, pwi = d.pwi, sri = d.sri, pssi = d.pssi, grade = d.grade, zero_reason = d.zero_reason, assessed_at = d.assessed_at, updated_by = d.updated_by, updated_at = now() FROM ( VALUES
(#{e.id}, #{e.taskId}, #{e.routeId}, #{e.sectionId}, #{e.unitId}, #{e.routeCode}, #{e.direction}, #{e.startStake}, #{e.endStake}, #{e.mqi}, #{e.sci}, #{e.pqi}, #{e.bci}, #{e.tci}, #{e.pci}, #{e.rqi}, #{e.rdi}, #{e.pbi}, #{e.pwi}, #{e.sri}, #{e.pssi}, #{e.grade}, #{e.zeroReason}, #{e.assessedAt}, #{userId})
) AS d(id, task_id, route_id, section_id, unit_id, route_code, direction, start_stake, end_stake, mqi, sci, pqi, bci, tci, pci, rqi, rdi, pbi, pwi, sri, pssi, grade, zero_reason, assessed_at, updated_by) WHERE t.tenant_id = #{tenantId} AND t.id = d.id AND t.deleted = false
